SELECT COUNT(m.id) FROM message m LEFT JOIN user u ON m.user_id = u.id
AND m.state = #{state}
AND (m.content LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))

SELECT m.id, m.user_id as userId, m.content, m.create_time as createTime, m.state, m.parent_id as parentId, m.reply_user_id as replyUserId, m.reject_reason as rejectReason, u.nickname, u.photo, ru.nickname as replyNickname FROM message m LEFT JOIN user u ON m.user_id = u.id LEFT JOIN user ru ON m.reply_user_id = ru.id
AND m.state = #{state}
AND (m.content LIKE CONCAT('%', #{keyword}, '%') OR u.nickname LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY m.create_time DESC LIMIT #{offset}, #{pageSize}

